li.NOResult:
if me:GetGLevel() >= 10 then
me:AddMsg(XT("[NAME] runs the primordial spirit and violently cracks the magic circle with a tyrannical cultivation base, but it seems that the chance is a little worse: the power of the magic circle's destruction has spread to the inheritance itself and destroyed, [NAME] secretly sighed, Had to leave."));me:AddSchoolScore(1,100);story:FinishSecret();
else
me:AddMsg(XT("[NAME] tried to violently crack the formation, but it was too overwhelmed, was seriously injured by the formation counterattack, and became the laughing stock of the spiritual world."));me:AddSchoolScore(1 ,- 300);me:AddDamgeFromCache(story.DamageCache,4);story:FinishSecret();
end;

li.OKResult:
if me:GetMatchingWithGong("SoulColor_1") >= 1 then
me:AddMsg(XT("[NAME] stepped forward to accept the test of the formation method, it was very suitable for this orthodoxy, and successfully accepted the inheritance of the orthodoxy."));me:DropAwardItem("Item_Dan_TreeEXP", 1);me:UnLockGong ("SoulColor_1");story:FinishSecret();
else
me:AddMsg(XT("[NAME] stepped forward to accept the formation test, but unfortunately it did not pass the formation test in the end, so I had no choice but to leave"));
end

